package com.taskflow.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.dto.LoginRequest;
import com.taskflow.dto.RegisterRequest;
import com.taskflow.entity.Task;
import com.taskflow.repository.TaskRepository;
import com.taskflow.repository.UserRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;
import org.springframework.transaction.annotation.Transactional;

import static org.hamcrest.Matchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
@Transactional
class TaskControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TaskRepository taskRepository;

    private String authToken;

    @BeforeEach
    void setUp() throws Exception {
        taskRepository.deleteAll();
        userRepository.deleteAll();

        // Register + login to get a JWT token
        RegisterRequest reg = new RegisterRequest();
        reg.setUsername("taskuser");
        reg.setPassword("password123");
        reg.setDisplayName("Task User");

        mockMvc.perform(post("/api/auth/register")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(reg)))
                .andExpect(status().isCreated());

        LoginRequest login = new LoginRequest();
        login.setUsername("taskuser");
        login.setPassword("password123");

        MvcResult loginResult = mockMvc.perform(post("/api/auth/login")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(login)))
                .andExpect(status().isOk())
                .andReturn();

        JsonNode loginJson = objectMapper.readTree(loginResult.getResponse().getContentAsString());
        authToken = loginJson.get("token").asText();
    }

    // ========== Helper Methods ==========

    private String taskJson(String title, String description, String priority) throws Exception {
        StringBuilder sb = new StringBuilder("{");
        sb.append("\"title\":\"").append(title).append("\"");
        if (description != null) {
            sb.append(",\"description\":\"").append(description).append("\"");
        }
        if (priority != null) {
            sb.append(",\"priority\":\"").append(priority).append("\"");
        }
        sb.append("}");
        return sb.toString();
    }

    private MvcResult createTaskAndReturn(String title, String description, String priority) throws Exception {
        return mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(taskJson(title, description, priority)))
                .andExpect(status().isCreated())
                .andReturn();
    }

    private Long createTaskGetId(String title, String description, String priority) throws Exception {
        MvcResult result = createTaskAndReturn(title, description, priority);
        JsonNode json = objectMapper.readTree(result.getResponse().getContentAsString());
        return json.get("id").asLong();
    }

    // =============================================
    // POST /api/tasks
    // =============================================

    @Nested
    class CreateTaskEndpoint {

        // AC1: create task returns 201 with TaskResponse
        @Test
        void shouldReturn201WithTaskResponse() throws Exception {
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(taskJson("My Task", "My Description", "HIGH")))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.id").isNumber())
                    .andExpect(jsonPath("$.title").value("My Task"))
                    .andExpect(jsonPath("$.description").value("My Description"))
                    .andExpect(jsonPath("$.priority").value("HIGH"))
                    .andExpect(jsonPath("$.status").value("TODO"))
                    .andExpect(jsonPath("$.createdBy").isNumber())
                    .andExpect(jsonPath("$.createdAt").exists());
        }

        // AC2: default priority MEDIUM when not specified
        @Test
        void shouldDefaultPriorityToMedium() throws Exception {
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"No Priority Task\"}"))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.priority").value("MEDIUM"));
        }

        // AC3: missing title returns 400
        @Test
        void shouldReturn400_whenTitleMissing() throws Exception {
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"description\":\"No title\"}"))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC3: blank title returns 400
        @Test
        void shouldReturn400_whenTitleBlank() throws Exception {
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"   \"}"))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC15: title > 200 chars returns 400
        @Test
        void shouldReturn400_whenTitleTooLong() throws Exception {
            String longTitle = "a".repeat(201);
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"" + longTitle + "\"}"))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC15: title exactly 200 chars should succeed
        @Test
        void shouldReturn201_whenTitleExactly200Chars() throws Exception {
            String title200 = "a".repeat(200);
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"" + title200 + "\"}"))
                    .andExpect(status().isCreated())
                    .andExpect(jsonPath("$.title").value(title200));
        }

        // AC16: description > 5000 chars returns 400
        @Test
        void shouldReturn400_whenDescriptionTooLong() throws Exception {
            String longDesc = "b".repeat(5001);
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"Valid\",\"description\":\"" + longDesc + "\"}"))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC16: description exactly 5000 chars should succeed
        @Test
        void shouldReturn201_whenDescriptionExactly5000Chars() throws Exception {
            String desc5000 = "c".repeat(5000);
            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"Valid\",\"description\":\"" + desc5000 + "\"}"))
                    .andExpect(status().isCreated());
        }
    }

    // =============================================
    // GET /api/tasks/{id}
    // =============================================

    @Nested
    class GetTaskEndpoint {

        // AC4: get task by id returns 200 with TaskResponse
        @Test
        void shouldReturn200WithTask() throws Exception {
            Long taskId = createTaskGetId("Get Me", "Desc", "HIGH");

            mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.id").value(taskId))
                    .andExpect(jsonPath("$.title").value("Get Me"))
                    .andExpect(jsonPath("$.description").value("Desc"))
                    .andExpect(jsonPath("$.priority").value("HIGH"));
        }

        // AC5: get non-existent task returns 404
        @Test
        void shouldReturn404_whenTaskNotFound() throws Exception {
            mockMvc.perform(get("/api/tasks/99999")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC9: get soft-deleted task returns 404
        @Test
        void shouldReturn404_whenTaskSoftDeleted() throws Exception {
            Long taskId = createTaskGetId("To Delete", "Desc", null);

            // Soft delete
            mockMvc.perform(delete("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());

            // Try to get
            mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound())
                    .andExpect(jsonPath("$.message").exists());
        }
    }

    // =============================================
    // PUT /api/tasks/{id}
    // =============================================

    @Nested
    class UpdateTaskEndpoint {

        // AC6: update task returns 200
        @Test
        void shouldReturn200WithUpdatedTask() throws Exception {
            Long taskId = createTaskGetId("Original", "Original Desc", "LOW");

            mockMvc.perform(put("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(taskJson("Updated", "Updated Desc", "HIGH")))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.title").value("Updated"))
                    .andExpect(jsonPath("$.description").value("Updated Desc"))
                    .andExpect(jsonPath("$.priority").value("HIGH"));
        }

        // AC6: update non-existent returns 404
        @Test
        void shouldReturn404_whenTaskNotFound() throws Exception {
            mockMvc.perform(put("/api/tasks/99999")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(taskJson("Updated", null, null)))
                    .andExpect(status().isNotFound())
                    .andExpect(jsonPath("$.message").exists());
        }

        // update with validation error (blank title) returns 400
        @Test
        void shouldReturn400_whenUpdateTitleBlank() throws Exception {
            Long taskId = createTaskGetId("Original", "Desc", null);

            mockMvc.perform(put("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{\"title\":\"   \"}"))
                    .andExpect(status().isBadRequest());
        }
    }

    // =============================================
    // DELETE /api/tasks/{id}
    // =============================================

    @Nested
    class DeleteTaskEndpoint {

        // AC7: delete returns 204
        @Test
        void shouldReturn204() throws Exception {
            Long taskId = createTaskGetId("To Delete", "Desc", null);

            mockMvc.perform(delete("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());
        }

        // AC7: delete non-existent returns 404
        @Test
        void shouldReturn404_whenTaskNotFound() throws Exception {
            mockMvc.perform(delete("/api/tasks/99999")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound())
                    .andExpect(jsonPath("$.message").exists());
        }

        // AC8: soft-deleted task should not appear in list
        @Test
        void shouldNotAppearInList_afterSoftDelete() throws Exception {
            Long taskId = createTaskGetId("Will Be Deleted", "Desc", null);

            mockMvc.perform(delete("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());

            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.content[?(@.id == " + taskId + ")]").doesNotExist());
        }
    }

    // =============================================
    // GET /api/tasks (list with pagination)
    // =============================================

    @Nested
    class ListTasksEndpoint {

        // AC10: list returns paginated response
        @Test
        void shouldReturnPaginatedResponse() throws Exception {
            createTaskGetId("Task 1", "Desc 1", "HIGH");
            createTaskGetId("Task 2", "Desc 2", "LOW");

            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.content").isArray())
                    .andExpect(jsonPath("$.content", hasSize(2)))
                    .andExpect(jsonPath("$.page").value(0))
                    .andExpect(jsonPath("$.size").value(20))
                    .andExpect(jsonPath("$.totalElements").value(2))
                    .andExpect(jsonPath("$.totalPages").value(1));
        }

        // AC10: empty list
        @Test
        void shouldReturnEmptyPage_whenNoTasks() throws Exception {
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.content").isArray())
                    .andExpect(jsonPath("$.content", hasSize(0)))
                    .andExpect(jsonPath("$.totalElements").value(0));
        }

        // AC11: keyword search filters by title
        @Test
        void shouldFilterByKeyword() throws Exception {
